sql:
SELECT COUNT(*) 
FROM commit_metadata 
WHERE key = 'reviewed_by';

SELECT MAX(total_changes) AS highest_total_changes
FROM (
    SELECT file_name, SUM(changes) AS total_changes
    FROM commits
    GROUP BY file_name
) AS file_changes;

